interface.signature:
interface BasicOperationsProps {
  operationType: 'addition' | 'subtraction';
  operand1: number;
  operand2: number;
  correctAnswer: number;
  onAnswer: (result: BasicOperationsResult) => void;
}

interface BasicOperationsResult {
  userAnswer: number;
  isCorrect: boolean;
  timeToAnswer: number;
  operationType: string;
  correctAnswer: number;
}

interface WordProblemProps {
  problemText: string;
  correctAnswer: number;
  onAnswer: (result: WordProblemResult) => void;
}

interface WordProblemResult {
  userAnswer: number;
  isCorrect: boolean;
  timeToAnswer: number;
  problemText: string;
  correctAnswer: number;
}

interface NumberKeypadProps {
  value: string;
  onChange: (value: string) => void;
  onSubmit: () => void;
  maxDigits?: number; // default 4
  disabled?: boolean;
  'data-testid'?: string;
}

export function generateBasicOperationsConfig(
  id: string,
  seed?: number
): BasicOperationsConfig {
  return {
    type: 'basic-operations',
    id,
    operationType: 'addition' | 'subtraction',
    operand1: number, // 1-20 for easy, 10-50 for medium, 20-99 for hard
    operand2: number,
    correctAnswer: number
  };
}

export function generateWordProblemConfig(
  id: string,
  seed?: number
): WordProblemConfig {
  return {
    type: 'word-problem',
    id,
    problemText: string, // Template with substituted values
    correctAnswer: number,
    context: 'apples' | 'coins' | 'toys' | 'books' // Simple contexts
  };
}

interface QuestionCardProps {
  question: string;
  children: React.ReactNode;
  footer?: React.ReactNode;
  'data-testid'?: string;
}
